THOUGHT: The crash occurs during constant folding when reading bytes from a constant global with non-byte-aligned integer types (i40). The function ReadDataFromGlobal in ConstantFolding.cpp uses APInt::extractBits and assumes the requested bit range lies within the APInt bitwidth. Accessing struct padding or crossing element boundaries can compute a bitPosition beyond BitWidth, triggering the assertion. I will inspect the repository to locate ConstantFolding.cpp and implement a bounds check in ReadDataFromGlobal to safely return zero for out-of-range bit requests, preventing the crash while preserving folding behavior for valid ranges.

```bash
nl -ba llvm/lib/Analysis/ConstantFolding.cpp | sed -n '420,520p' && sed -n '520,780p' llvm/lib/Analysis/ConstantFolding.cpp && applypatch << 'PATCH'
*** Begin Patch
*** Update File: llvm/lib/Analysis/ConstantFolding.cpp
@@
 static bool ReadDataFromGlobal(Constant *C, unsigned long ByteOffset,
                                unsigned char *Dest, unsigned NumBytes,
                                const DataLayout &DL) {
@@
-    // Read NumBytes starting at ByteOffset out of the APInt.
-    unsigned BitOffset = ByteOffset * 8;
-    unsigned NumBits = NumBytes * 8;
-    APInt Bits = AI.extractBits(NumBits, BitOffset);
+    // Read NumBytes starting at ByteOffset out of the APInt.
+    // Guard against illegal bit extraction when the requested range
+    // exceeds the APInt bitwidth, which can happen when reading
+    // bytes from padding or crossing element boundaries in aggregates
+    // containing non-byte-sized integers (e.g., i40).
+    unsigned BitOffset = ByteOffset * 8;
+    unsigned NumBits = NumBytes * 8;
+    unsigned BW = AI.getBitWidth();
+    // If the requested bit range is fully outside the APInt, treat as zero.
+    if (BitOffset >= BW) {
+      std::memset(Dest, 0, NumBytes);
+      return true;
+    }
+    // Clamp NumBits so that BitOffset + NumBits does not exceed BW.
+    if (BitOffset + NumBits > BW)
+      NumBits = BW - BitOffset;
+    APInt Bits = AI.extractBits(NumBits, BitOffset);
@@
-    // Copy the bits into Dest. Note that extractBits returns the bits
-    // right-adjusted (i.e., filling from LSB), so we need to write out
-    // as little-endian bytes.
-    for (unsigned I = 0; I != NumBytes; ++I) {
-      unsigned Shift = I * 8;
-      Dest[I] = (unsigned char)Bits.extractBits(8, Shift).getZExtValue();
-    }
+    // Copy the bits into Dest. Note that extractBits returns the bits
+    // right-adjusted (i.e., filling from LSB), so we need to write out
+    // as little-endian bytes. Any bytes beyond NumBits (due to clamping)
+    // are zero-filled to represent padding/absent data.
+    unsigned FilledBytes = NumBits / 8;
+    for (unsigned I = 0; I != FilledBytes; ++I) {
+      unsigned Shift = I * 8;
+      Dest[I] = (unsigned char)Bits.extractBits(8, Shift).getZExtValue();
+    }
+    if (FilledBytes < NumBytes)
+      std::memset(Dest + FilledBytes, 0, NumBytes - FilledBytes);
     return true;
   }
*** End Patch
PATCH
 && ninja -C llvm-build/144279 && cat /tmp/test.ll && llvm-build/144279/bin/opt /tmp/test.ll -passes=instsimplify -S && submit-patch

